import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline
import math

# Define fused GEMM + GroupNorm + HardTanh CUDA kernel
fused_kernel_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <cublas_v2.h>

template<typename T>
__global__ void fused_gemm_groupnorm_hardtanh_kernel(
    const T* __restrict__ gemm_output,
    T* __restrict__ output,
    const int batch_size,
    const int out_features,
    const int num_groups,
    const float eps,
    const float min_val,
    const float max_val) {

    const int group_size = out_features * num_groups;
    const int group_idx = blockIdx.x % num_groups;
    const int batch_idx = blockIdx.x / num_groups;

    if (batch_idx >= batch_size) return;

    const int tid = threadIdx.x;
    const int feature_idx = tid;

    if (feature_idx >= group_size) return;

    const int output_idx = batch_idx * out_features + group_idx * group_size + feature_idx;

    // Load this thread's value
    float val = static_cast<float>(gemm_output[output_idx]);

    // Shared memory for reduction
    __shared__ float shared_sum[32];
    __shared__ float shared_sum_sq[32];
    __shared__ float shared_mean;
    __shared__ float shared_inv_std;

    // Warp reduction for mean and variance
    float warp_sum = 0.0f;
    float warp_sum_sq = 0.0f;

    // Each warp handles multiple elements if group_size > 32
    for (int i = feature_idx; i < group_size; i += blockDim.x) {
        int idx = batch_idx * out_features + group_idx * group_size + i;
        float element = static_cast<float>(gemm_output[idx]);
        warp_sum += element;
        warp_sum_sq += element * element;
    }

    // Reduce within warp
    for (int offset = 16; offset > 0; offset /= 2) {
        warp_sum += __shfl_down_sync(0xffffffff, warp_sum, offset);
        warp_sum_sq += __shfl_down_sync(0xffffffff, warp_sum_sq, offset);
    }

    // First thread in warp stores to shared memory
    if (tid % 32 == 0) {
        shared_sum[tid / 32] = warp_sum;
        shared_sum_sq[tid / 32] = warp_sum_sq;
    }

    __syncthreads();

    // Final reduction across warps (only first warp does this)
    if (tid < 32) {
        float total_sum = 0.0f;
        float total_sum_sq = 0.0f;

        int num_warps = (group_size + 31) / 32;
        if (tid < num_warps) {
            total_sum = shared_sum[tid];
            total_sum_sq = shared_sum_sq[tid];
        }

        // Reduce across warps
        for (int offset = 16; offset > 0; offset /= 2) {
            total_sum += __shfl_down_sync(0xffffffff, total_sum, offset);
            total_sum_sq += __shfl_down_sync(0xffffffff, total_sum_sq, offset);
        }

        if (tid == 0) {
            float mean = total_sum / group_size;
            float variance = (total_sum_sq / group_size) - (mean * mean);
            float inv_std = rsqrtf(variance + eps);
            shared_mean = mean;
            shared_inv_std = inv_std;
        }
    }

    __syncthreads();

    // Apply normalization and HardTanh
    if (feature_idx < group_size) {
        float normalized = (val - shared_mean) * shared_inv_std;
        float clipped = fminf(fmaxf(normalized, min_val), max_val);
        output[output_idx] = static_cast<T>(clipped);
    }
}

torch::Tensor fused_groupnorm_hardtanh_cuda(
    torch::Tensor gemm_output,
    int num_groups,
    float eps,
    float min_val,
    float max_val) {

    auto batch_size = gemm_output.size(0);
    auto out_features = gemm_output.size(1);
    const int group_size = out_features / num_groups;

    auto output = torch::empty_like(gemm_output);

    // Each block handles one group for one batch
    dim3 grid_dim(batch_size * num_groups);

    // Use 256 threads per block for better occupancy
    const int threads_per_block = 256;

    AT_DISPATCH_FLOATING_TYPES(gemm_output.scalar_type(), "fused_groupnorm_hardtanh", [&] {
        fused_gemm_groupnorm_hardtanh_kernel<scalar_t><<<grid_dim, threads_per_block>>>(
            gemm_output.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            batch_size,
            out_features,
            num_groups,
            eps,
            min_val,
            max_val);
    });

    return output;
}
