        super(ModelNew, self).__init__()

        assert out_features % num_groups == 0, "out_features must be divisible by num_groups"

        self.in_features = in_features
        self.out_features = out_features
        self.num_groups = num_groups
        self.hardtanh_min = hardtanh_min
        self.hardtanh_max = hardtanh_max
        self.eps = 1e-5

        # Use PyTorch's optimized Linear layer for GEMM
        self.gemm = nn.Linear(in_features, out_features)

        # Store the fused operation
        self.fused_op = fused_op

    def forward(self, x):
        # Use PyTorch's optimized GEMM
        gemm_output = self.gemm(x)

        # Apply fused GroupNorm + HardTanh
        return self.fused_op.fused_groupnorm_hardtanh_cuda(
            gemm_output,
            self.num_groups,
            self.eps,
            self.hardtanh_min,
            self.hardtanh_max
        )

